    fputc(0x01, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f);

    // Pixel data: 16 pixels * 4 bytes = 64 bytes
    // Each pixel: R=0, G=0, B=0, A=1 (opacity != MaxRGB)
    for (int i = 0; i < 16; i++) {
